import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  // Scroll logic for sticky effect
  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Electronics', path: '/electronics' },
    { name: 'Electrical', path: '/electrical' },
    { name: 'Chemical', path: '/chemical' },
    { name: 'Industries', path: '/industries' },
    { name: 'About Us', path: '/about' },
    { name: 'Careers', path: '/careers' },
  ];

  return (
    <>
      <nav className={`fixed w-full z-[100] top-0 left-0 transition-all duration-300 ${
        scrolled ? 'bg-white shadow-md py-3' : 'bg-white/80 backdrop-blur-md py-5'
      }`}>
        <div className="max-w-[1440px] mx-auto px-6 md:px-12 flex justify-between items-center">

          {/* Logo */}
          <Link to="/" className="flex items-center gap-1 group">
            <span className="text-3xl font-black tracking-tighter text-gray-900">HUDSON</span>
            <span className="h-2 w-2 rounded-full bg-orange-600 mt-2 animate-pulse"></span>
          </Link>

          {/* 1. Desktop Navigation (Links yahan dikhenge) */}
          <div className="hidden lg:flex items-center space-x-8">
            {navLinks.map((link) => (
              <Link
                key={link.name}
                to={link.path}
                className={`text-sm font-bold uppercase tracking-widest transition-all ${
                  location.pathname === link.path ? 'text-orange-600' : 'text-gray-500 hover:text-orange-600'
                }`}
              >
                {link.name}
              </Link>
            ))}
          </div>

          {/* 2. Desktop CTA */}
          <div className="hidden md:flex items-center gap-4">
            <button className="bg-gray-950 text-white px-7 py-2.5 rounded-full font-bold text-xs uppercase tracking-widest hover:bg-orange-600 transition-all shadow-lg">
              Contact
            </button>
          </div>

          {/* 3. Mobile Hamburger Button (Sirf mobile par dikhega) */}
          <button 
            onClick={() => setIsOpen(true)}
            className="lg:hidden p-2 text-gray-900"
          >
            <div className="space-y-1.5">
              <span className="block w-6 h-0.5 bg-gray-900"></span>
              <span className="block w-6 h-0.5 bg-gray-900"></span>
              <span className="block w-4 h-0.5 bg-gray-900"></span>
            </div>
          </button>
        </div>
      </nav>

      {/* 4. Mobile Side Drawer (Jo 'Menu' click karne par aayega) */}
      <div className={`fixed inset-0 z-[200] transition-all duration-500 ${isOpen ? 'visible' : 'invisible'}`}>
        {/* Overlay Background */}
        <div 
          className={`absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity duration-500 ${isOpen ? 'opacity-100' : 'opacity-0'}`}
          onClick={() => setIsOpen(false)}
        ></div>

        {/* Side Panel */}
        <div className={`absolute right-0 top-0 h-full w-[300px] bg-white shadow-2xl transition-transform duration-500 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="p-8 flex flex-col h-full">
            <div className="flex justify-between items-center mb-12">
              <span className="font-black text-xl">MENU</span>
              <button onClick={() => setIsOpen(false)} className="text-3xl font-light">&times;</button>
            </div>

            <div className="space-y-6">
              {navLinks.map((link) => (
                <Link
                  key={link.name}
                  to={link.path}
                  onClick={() => setIsOpen(false)}
                  className="block text-2xl font-bold text-gray-900 hover:text-orange-600 transition-all tracking-tight"
                >
                  {link.name}
                </Link>
              ))}
            </div>

            <div className="mt-auto">
              <button className="w-full bg-orange-600 text-white py-4 rounded-2xl font-bold">
                Get in Touch
              </button>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default Navbar;
